export type ParsedSlashInstruction<
  TProgram extends string = typeof STAKING_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    slashAuthority: TAccountMetas[0];
    config: TAccountMetas[1];
    position: TAccountMetas[2];
    vault: TAccountMetas[3];
    treasury: TAccountMetas[4];
    mint: TAccountMetas[5];
    programAuthority: TAccountMetas[6];
    nodeRegistryProgram: TAccountMetas[7];
    registry: TAccountMetas[8];
    node?: TAccountMetas[9] | undefined;
    tokenProgram: TAccountMetas[10];
  };
  data: SlashInstructionData;
};

export function parseSlashInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedSlashInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    throw new SolanaError(SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS, {
      actualAccountMetas: instruction.accounts.length,
      expectedAccountMetas: 11,
    });
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === STAKING_PROGRAM_ADDRESS ? undefined : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      slashAuthority: getNextAccount(),
      config: getNextAccount(),
      position: getNextAccount(),
      vault: getNextAccount(),
      treasury: getNextAccount(),
      mint: getNextAccount(),
      programAuthority: getNextAccount(),
      nodeRegistryProgram: getNextAccount(),
      registry: getNextAccount(),
      node: getNextOptionalAccount(),
      tokenProgram: getNextAccount(),
    },
    data: getSlashInstructionDataDecoder().decode(instruction.data),
  };
}
